#[derive(Debug, Clone, Copy)]
struct SearchBudget {
    label: &'static str,
    depth: i32,
    max_nodes: i32,
}

#[derive(Clone, Copy, Debug)]
struct BudgetConversionDiagnostic {
    fast_wins: usize,
    fast_losses: usize,
    draws: usize,
    fast_win_rate: f64,
    normal_edge: f64,
    confidence: f64,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
enum EvalPhaseFamily {
    Fast,
    NormalBalanced,
    NormalTactical,
    NormalTacticalAggressive,
    NormalFinisher,
    NormalFinisherAggressive,
}

impl EvalPhaseFamily {
    fn as_str(self) -> &'static str {
        match self {
            Self::Fast => "fast",
            Self::NormalBalanced => "normal_balanced",
            Self::NormalTactical => "normal_tactical",
            Self::NormalTacticalAggressive => "normal_tactical_aggr",
            Self::NormalFinisher => "normal_finisher",
            Self::NormalFinisherAggressive => "normal_finisher_aggr",
        }
    }
}

#[derive(Clone)]
struct EvalTuningSample {
    mode: &'static str,
    phase_family: EvalPhaseFamily,
    fen: String,
    input: String,
    after_fen: String,
    after_game: MonsGame,
    perspective: Color,
    selected: bool,
    score: i32,
    best_score: i32,
    regret: i32,
    efficiency: i32,
    attack_drainer: bool,
    own_drainer_vulnerable: bool,
    mana_handoff: bool,
    roundtrip: bool,
    class_immediate_score: bool,
    class_drainer_attack: bool,
    class_drainer_safety_recover: bool,
    class_carrier_progress: bool,
    class_material: bool,
    class_quiet: bool,
    eval_total: i32,
    eval_confirmed_score: i32,
    eval_consumable_score: i32,
    eval_score_race_path: i32,
    eval_opp_score_race_path: i32,
    eval_score_race_multi: i32,
    eval_opp_score_race_multi: i32,
    eval_immediate_window: i32,
    eval_opp_immediate_window: i32,
    eval_immediate_multi: i32,
    eval_opp_immediate_multi: i32,
    eval_match_point: i32,
    eval_residual: i32,
}

impl SearchBudget {
    fn from_preference(preference: SmartAutomovePreference) -> Self {
        let (depth, max_nodes) = preference.depth_and_max_nodes();
        Self {
            label: preference.as_api_value(),
            depth,
            max_nodes,
        }
    }

    fn key(self) -> &'static str {
        self.label
    }

    fn runtime_config_for_game(self, game: &MonsGame) -> SmartSearchConfig {
        if let Some(preference) = SmartAutomovePreference::from_api_value(self.label) {
            let hinted_context = if matches!(
                preference,
                SmartAutomovePreference::Pro | SmartAutomovePreference::Ultra
            ) && env_bool("SMART_USE_WHITE_OPENING_BOOK").unwrap_or(false)
            {
                ProRuntimeContext::OpeningBookDriven
            } else {
                ProRuntimeContext::Unknown
            };
            MonsGameModel::runtime_config_for_game_with_context(game, preference, hinted_context).0
        } else {
            MonsGameModel::with_runtime_scoring_weights(
                game,
                SmartSearchConfig::from_budget(self.depth, self.max_nodes).for_runtime(),
            )
        }
    }
}

fn client_budgets() -> [SearchBudget; 2] {
    [
        SearchBudget::from_preference(SmartAutomovePreference::Fast),
        SearchBudget::from_preference(SmartAutomovePreference::Normal),
    ]
}

fn pro_budget() -> SearchBudget {
    SearchBudget::from_preference(SmartAutomovePreference::Pro)
}

fn ultra_budget() -> SearchBudget {
    SearchBudget::from_preference(SmartAutomovePreference::Ultra)
}

#[allow(dead_code)]
fn client_budgets_with_pro() -> [SearchBudget; 3] {
    [
        SearchBudget::from_preference(SmartAutomovePreference::Fast),
        SearchBudget::from_preference(SmartAutomovePreference::Normal),
        SearchBudget::from_preference(SmartAutomovePreference::Pro),
    ]
}

#[allow(dead_code)]
fn client_budgets_with_pro_ultra() -> [SearchBudget; 4] {
    [
        SearchBudget::from_preference(SmartAutomovePreference::Fast),
        SearchBudget::from_preference(SmartAutomovePreference::Normal),
        SearchBudget::from_preference(SmartAutomovePreference::Pro),
        SearchBudget::from_preference(SmartAutomovePreference::Ultra),
    ]
}

